#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>

#define NPAIRS 32
#define N 0x100000

typedef struct { uint64_t p, c; } Pair;
static Pair pairs[NPAIRS];

static uint32_t ek[4][N];

static inline uint8_t g(uint8_t a, uint8_t b, uint8_t x){
    uint8_t t=(a+b+x)&0xFF;
    return (t<<2)|(t>>6);
}
static inline uint32_t f(uint32_t v){
    uint8_t x[4],y[4];
    for(int i=0;i<4;i++){x[i]=v&0xFF;v>>=8;}
    y[2]=g(x[3]^x[2],x[1]^x[0],1);
    y[3]=g(x[3],y[2],0);
    y[1]=g(x[1]^x[0],y[2],0);
    y[0]=g(x[0],y[1],1);
    uint32_t r=0;
    for(int i=0;i<4;i++) r|=(uint32_t)y[i]<<(8*i);
    return r;
}
static inline void fwd2(uint64_t pt,uint32_t k0,uint32_t k1,uint32_t *L,uint32_t *R){
    uint32_t l=(uint32_t)(pt>>32), r=(uint32_t)pt;
    r^=l;
    uint32_t t=r; r=l^f(r^k0); l=t;
    t=r; r=l^f(r^k1); l=t;
    *L=l;*R=r;
}
static inline void bwd2(uint64_t ct,uint32_t k2,uint32_t k3,uint32_t *L,uint32_t *R){
    uint32_t l=(uint32_t)ct, r=(uint32_t)(ct>>32);
    l^=r;
    uint32_t t=l; l=r; uint32_t m=f(t^k3); r=t; l^=m;
    t=l; l=r; m=f(t^k2); r=t; l^=m;
    *L=l;*R=r;
}
// For fixed s0,s3, use one pair to MITM s1/s2.
// Forward from pair0 after round1 depends on s0 only. After round2 depends on s0,s1.
// Backward from ciphertext after round3 inverse depends on s3 only. After round2 inverse depends on s2,s3.
// Match at boundary between round2 and round3: state after round2 forward equals state before round2 backward.
// This is same matching problem; implement per (s0,s3) with s1 table of size N.
int main(){
    FILE*fp=fopen("pairs.txt","r");
    if(!fp){perror("pairs.txt");return 1;}
    for(int i=0;i<NPAIRS;i++) if(fscanf(fp,"%lu %lu",&pairs[i].p,&pairs[i].c)!=2) return 1;
    fclose(fp);
    for(int i=0;i<4;i++) for(uint32_t s=0;s<N;s++) ek[i][s]=expand(s);

    // Pair0 states after round1 for each s0, before round3 for each s3
    static uint32_t L1[N],R1[N];
    for(uint32_t s0=0;s0<N;s0++){
        uint32_t l=(uint32_t)(pairs[0].p>>32), r=(uint32_t)pairs[0].p;
        r^=l;
        uint32_t t=r; r=l^f(r^ek[0][s0]); l=t;
        L1[s0]=l;R1[s0]=r;
    }
    static uint32_t L3[N],R3[N];
    for(uint32_t s3=0;s3<N;s3++){
        uint32_t l=(uint32_t)pairs[0].c, r=(uint32_t)(pairs[0].c>>32);
        l^=r;
        // after undoing final round? Actually before final round in encryption = after round2
        // reverse round3 gives state after round2
        uint32_t t=l; l=r; uint32_t m=f(t^ek[3][s3]); r=t; l^=m;
        L3[s3]=l;R3[s3]=r;
    }

    // For pair0, for each s3 we know required state after round2 (L3,R3). For a candidate s2, state before round2 forward? 
    // We need state after round2. Given state after round1 (L1,R1) and s1, state after round2 = {L2=R1, R2=L1^f(R1^s1)}.
    // Given state after round2 (L3,R3) and s2, state before round2 (after round1) = reverse one round = {L1=R3, R1=L3^f(R3^s2)}? Check.
    // forward round2: L2=R1, R2=L1^f(R1^s1). Thus R1=L2. And L1 = R2 ^ f(L2^s1) = R2 ^ f(R1^s1).
    // reverse round2: given L2,R2,s2: L1=R2 ^ f(L2^s2), R1=L2.
    for(uint32_t s3=0;s3<N;s3++){
        uint32_t L2=L3[s3],R2=R3[s3];
        for(uint32_t s2=0;s2<N;s2++){
            uint32_t R1=L2;
            uint32_t L1=R2 ^ f(L2^ek[2][s2]);
            // find s0 such that state after round1 equals (L1,R1)
            // Use hash table over s0 for (R1,L1). Build once? R1 is only 32 bits, hash by R1.
            // This is still O(N^3)=2^60. Need better.
            (void)L1;(void)R1;
        }
    }
    printf("not implemented\n");
    return 1;
}
